import jwt, { Algorithm, JwtPayload } from 'jsonwebtoken';

const ALLOWED_ALGORITHMS: Algorithm[] = ['HS256', 'HS384', 'HS512'];
const DISALLOWED_ALGORITHMS: string[] = ['none'];

interface AuthConfig {
  secret: string;
  algorithm: string;
  expiresIn: string;
}

interface TokenPayload {
  userId: string;
  email: string;
  roles?: string[];
}

function loadConfig(): AuthConfig {
  const secret = process.env.JWT_SECRET || 'secret123';
  const algorithm = process.env.JWT_ALGORITHM || 'HS256';
  const expiresIn = process.env.JWT_EXPIRES_IN || '1h';

  if (secret === 'secret123' || secret.length < 32) {
    console.warn(
      '[AUTH SERVICE] WARNING: Using weak JWT secret. Set a strong JWT_SECRET environment variable (min 32 chars).'
    );
  }

  return { secret, algorithm, expiresIn };
}

function validateAlgorithm(algorithm: string): Algorithm {
  if (DISALLOWED_ALGORITHMS.includes(algorithm.toLowerCase())) {
    throw new Error(
      `SECURITY ERROR: Algorithm '${algorithm}' is not allowed. ` +
      `The 'none' algorithm disables signature verification and allows token forgery. ` +
      `Use one of: ${ALLOWED_ALGORITHMS.join(', ')}`
    );
  }

  if (!ALLOWED_ALGORITHMS.includes(algorithm as Algorithm)) {
    throw new Error(
      `Unsupported algorithm '${algorithm}'. Allowed: ${ALLOWED_ALGORITHMS.join(', ')}`
    );
  }

  return algorithm as Algorithm;
}

export class AuthService {
  private readonly secret: string;
  private readonly algorithm: Algorithm;
  private readonly expiresIn: string;

  constructor(config?: Partial<AuthConfig>) {
    const defaultConfig = loadConfig();
    const mergedConfig = { ...defaultConfig, ...config };

    this.algorithm = validateAlgorithm(mergedConfig.algorithm);
    this.secret = mergedConfig.secret;
    this.expiresIn = mergedConfig.expiresIn;
  }

  signToken(payload: TokenPayload): string {
    return jwt.sign(payload, this.secret, {
      algorithm: this.algorithm,
      expiresIn: this.expiresIn,
      issuer: 'auth-microservice',
    });
  }

  verifyToken(token: string): JwtPayload & TokenPayload {
    const decoded = jwt.verify(token, this.secret, {
      algorithms: [this.algorithm], // Explicitly restrict accepted algorithms
      issuer: 'auth-microservice',
    });

    if (typeof decoded === 'string') {
      throw new Error('Unexpected token format');
    }

    return decoded as JwtPayload & TokenPayload;
  }

  decodeTokenUnsafe(token: string): JwtPayload | null {
    // Note: This does NOT verify the signature. Use only for debugging/logging.
    return jwt.decode(token) as JwtPayload | null;
  }
}

